package com.trademaster.ims.mobile.help.model;
import jakarta.persistence.*;
@Entity @Table(name="mobile_help_faqs",indexes={@Index(name="idx_faq_code",columnList="faq_code",unique=true),@Index(name="idx_faq_active_category",columnList="active,category,display_order")})
public class HelpFaq{ @Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="faq_code",nullable=false,unique=true,length=80)private String faqCode;@Column(nullable=false,length=80)private String category;@Column(nullable=false,length=240)private String question;@Column(nullable=false,columnDefinition="TEXT")private String answer;@Column(name="display_order",nullable=false)private int displayOrder;@Column(nullable=false)private boolean active=true;public Long getId(){return id;}public String getFaqCode(){return faqCode;}public void setFaqCode(String v){faqCode=v;}public String getCategory(){return category;}public void setCategory(String v){category=v;}public String getQuestion(){return question;}public void setQuestion(String v){question=v;}public String getAnswer(){return answer;}public void setAnswer(String v){answer=v;}public int getDisplayOrder(){return displayOrder;}public void setDisplayOrder(int v){displayOrder=v;}public boolean isActive(){return active;}public void setActive(boolean v){active=v;}}